export function getWritingSet(setId: string): WritingSet | undefined {
  return WRITING_SETS.find((s) => s.id === setId) || WRITING_SETS_HSK2.find((s) => s.id === setId) || WRITING_SETS_HSK2_L2.find((s) => s.id === setId) || WRITING_SETS_HSK3.find((s) => s.id === setId) || WRITING_SETS_HSK4.find((s) => s.id === setId);
}
